const marked = {
  parse(src) {
    let html = src;
    const spans = [];
    const protect = (str) => {
      const k = '\x02' + spans.length + '\x03';
      spans.push(str);
      return k;
    };
    const restore = (str) => str.replace(/\x02(\d+)\x03/g, (_, i) => spans[i]);
    html = html.replace(/```(\w*)\n?([\s\S]*?)```/g, (_, lang, code) => protect('<pre><code>' + code.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;') + '</code></pre>'));
    html = html.replace(/`([^`\n]+)`/g, (_, code) => protect('<code>' + code.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;') + '</code>'));
    html = html.replace(/^###### (.+)$/gm, '<h6>$1</h6>');
    html = html.replace(/^##### (.+)$/gm, '<h5>$1</h5>');
    html = html.replace(/^#### (.+)$/gm, '<h4>$1</h4>');
    html = html.replace(/^### (.+)$/gm, '<h3>$1</h3>');
    html = html.replace(/^## (.+)$/gm, '<h2>$1</h2>');
    html = html.replace(/^# (.+)$/gm, '<h1>$1</h1>');
    html = html.replace(/^(-{3,}|\*{3,}|_{3,})$/gm, '<hr>');
    html = html.replace(/^> (.+)$/gm, '<blockquote>$1</blockquote>');
    html = html.replace(/\*\*\*(.+?)\*\*\*/g, '<strong><em>$1</em></strong>');
    html = html.replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>');
    html = html.replace(/\*(.+?)\*/g, '<em>$1</em>');
    html = html.replace(/~~(.+?)~~/g, '<del>$1</del>');
    html = html.replace(/!\[([^\]]*)\]\(([^)]+)\)/g, '<img alt="$1" src="$2">');
    html = html.replace(/\[([^\]]+)\]\(([^)]+)\)/g, '<a href="$2">$1</a>');
    html = html.replace(/((?:^[ \t]*[-*+] .+\n?)+)/gm, match => '<ul>' + match.trim().split('\n').map(l => '<li>' + l.replace(/^[ \t]*[-*+] /, '') + '</li>').join('') + '</ul>\n');
    html = html.replace(/((?:^\d+\. .+\n?)+)/gm, match => '<ol>' + match.trim().split('\n').map(l => '<li>' + l.replace(/^\d+\. /, '') + '</li>').join('') + '</ol>\n');
    html = html.replace(/^(?!<[a-z]|\x02|$)(.+)$/gm, '<p>$1</p>');
    html = html.replace(/\n{3,}/g, '\n\n');
    return restore(html);
  }
};
module.exports = { marked };
